CREATE SCHEMA IF NOT EXISTS catalog;

CREATE TABLE IF NOT EXISTS catalog.items (
    id UUID NOT NULL DEFAULT gen_random_uuid(),
    item_code TEXT NOT NULL,
    name TEXT NOT NULL,
    description TEXT,
    barcode TEXT,
    brand_id UUID,
    item_group_id UUID NOT NULL,
    default_uom_id UUID NOT NULL,
    item_type item_type NOT NULL DEFAULT 'physical_good',
    is_sales_item BOOLEAN NOT NULL DEFAULT TRUE,
    is_purchase_item BOOLEAN NOT NULL DEFAULT TRUE,
    is_stock_item BOOLEAN NOT NULL DEFAULT TRUE,
    has_variants BOOLEAN NOT NULL DEFAULT FALSE,
    hsn_code TEXT,
    sni TEXT,
    is_taxable BOOLEAN NOT NULL DEFAULT TRUE,
    weight_per_unit NUMERIC(18, 4),
    shelf_life_days INTEGER CHECK (shelf_life_days >= 0),
    tags JSONB NOT NULL DEFAULT '[]'::jsonb,
    data JSONB NOT NULL DEFAULT '{}'::jsonb,
    status catalog_status NOT NULL DEFAULT 'active',
    metadata JSONB NOT NULL DEFAULT '{"created_at":null,"updated_at":null,"deleted_at":null,"created_by":null,"updated_by":null,"deleted_by":null}'::jsonb,
    PRIMARY KEY (id)
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_items_item_code ON catalog.items (item_code) WHERE (metadata->>'deleted_at') IS NULL;

CREATE UNIQUE INDEX IF NOT EXISTS idx_items_barcode ON catalog.items (barcode) WHERE barcode IS NOT NULL AND (metadata->>'deleted_at') IS NULL;

