-- GIN index for audit metadata JSONB queries
CREATE INDEX IF NOT EXISTS idx_items_metadata_gin ON catalog.items USING GIN (metadata);
CREATE INDEX IF NOT EXISTS idx_items_metadata_deleted_at ON catalog.items ((metadata->>'deleted_at'));
CREATE INDEX IF NOT EXISTS idx_items_metadata_created_at ON catalog.items ((metadata->>'created_at'));
CREATE INDEX IF NOT EXISTS idx_items_metadata_updated_at ON catalog.items ((metadata->>'updated_at'));

-- Triggers for automatic metadata timestamp management
-- Automatically sets created_at on INSERT and updated_at on UPDATE

-- Function to set metadata->'created_at' on INSERT
CREATE OR REPLACE FUNCTION catalog.items_audit_timestamp() RETURNS trigger AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        NEW.metadata = jsonb_set(NEW.metadata::jsonb, '{created_at}', to_jsonb(NOW()));
        NEW.metadata = jsonb_set(NEW.metadata::jsonb, '{updated_at}', to_jsonb(NOW()));
    ELSIF TG_OP = 'UPDATE' THEN
        NEW.metadata = jsonb_set(NEW.metadata::jsonb, '{updated_at}', to_jsonb(NOW()));
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Trigger to set timestamps on INSERT
DROP TRIGGER IF EXISTS items_insert_audit ON catalog.items;
CREATE TRIGGER items_insert_audit BEFORE INSERT ON catalog.items
    FOR EACH ROW EXECUTE FUNCTION catalog.items_audit_timestamp();

-- Trigger to set updated_at on UPDATE
DROP TRIGGER IF EXISTS items_update_audit ON catalog.items;
CREATE TRIGGER items_update_audit BEFORE UPDATE ON catalog.items
    FOR EACH ROW EXECUTE FUNCTION catalog.items_audit_timestamp();

